fixed_code:
fn main() {
    #[derive(Debug)]
    struct Person { name: String, age: u8 }

    let mut people = vec![Person { name: "Alice".to_string(), age: 30 },
                          Person { name: "Bob".to_string(), age: 25 }];

    // Correctly use sort_unstable_by_key for simple key extraction
    people.sort_unstable_by_key(|p| p.age);

    for p in people {
        println!("{} is {}", p.name, p.age);
    }
}

